+        );
+        assert!(
+            !dir_icon.contains('\u{FE0F}'),
+            "directory icon contains VS16"
+        );
+
+        let sym_icon = icons::symlink_icon();
+        assert_eq!(
+            grapheme_width(sym_icon),
+            ICON_COL_WIDTH,
+            "symlink icon width"
+        );
